import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class GsonTest {

  @Test
  public void testHtmlSafe_defaultTrue() throws Exception {
    Gson gson = new Gson();

    // Access private final field htmlSafe via reflection
    Field htmlSafeField = Gson.class.getDeclaredField("htmlSafe");
    htmlSafeField.setAccessible(true);

    // By default, htmlSafe should be true as per DEFAULT_ESCAPE_HTML constant
    boolean htmlSafeValue = htmlSafeField.getBoolean(gson);
    assertTrue(htmlSafeValue);

    // Call the method and verify it returns the field value
    boolean result = gson.htmlSafe();
    assertEquals(htmlSafeValue, result);
  }

  @Test
  public void testHtmlSafe_reflectSetFalse() throws Exception {
    Gson gson = new Gson();

    // Set the private final field htmlSafe to false via reflection
    Field htmlSafeField = Gson.class.getDeclaredField("htmlSafe");
    htmlSafeField.setAccessible(true);

    // Remove final modifier using reflection hacks
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(htmlSafeField, htmlSafeField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    htmlSafeField.setBoolean(gson, false);

    // Call the method and verify it returns the updated field value
    boolean result = gson.htmlSafe();
    assertFalse(result);
  }
}
